import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is time value of money?", a: "Time value of money is the idea that money today is worth more than the same amount in the future because it can earn interest or investment returns." },
  { q: "What is present value?", a: "Present value is the current value of a future amount, discounted by a selected interest rate over a number of periods." },
  { q: "What is future value?", a: "Future value is what a present amount and recurring payments may grow to after interest compounds over time." },
  { q: "How do you calculate the interest rate from PV and FV?", a: "For a lump sum without payments, rate can be estimated with Rate = (FV / PV)^(1 / n) - 1. With payments, a numerical solver is typically used." },
  { q: "How is TVM used in financial decisions?", a: "TVM is used for loans, investing, retirement planning, bond valuation, savings goals, and comparing cash flows across time." },
];

type SolveFor = "pv" | "fv" | "n" | "rate" | "pmt";
const money = (value: number, digits = 2) => formatCurrencyValue(value, { maximumFractionDigits: digits });
const tvmFv = (pv: number, pmt: number, ratePct: number, periods: number) => {
  const r = ratePct / 100;
  if (r === 0) return pv + pmt * periods;
  return pv * Math.pow(1 + r, periods) + pmt * ((Math.pow(1 + r, periods) - 1) / r);
};
const solveRate = (pv: number, fv: number, pmt: number, periods: number) => {
  let low = -0.99;
  let high = 1;
  for (let i = 0; i < 100; i += 1) {
    const mid = (low + high) / 2;
    const guess = tvmFv(pv, pmt, mid * 100, periods);
    if (guess > fv) high = mid; else low = mid;
  }
  return ((low + high) / 2) * 100;
};

export default function FinanceCalculator() {
  useCurrencyVersion();
  const [solveFor, setSolveFor] = useState<SolveFor>("fv");
  const [pv, setPv] = useState(1000);
  const [fv, setFv] = useState(2000);
  const [periods, setPeriods] = useState(10);
  const [rate, setRate] = useState(7);
  const [payment, setPayment] = useState(100);

  const result = useMemo(() => {
    const r = rate / 100;
    if (solveFor === "fv") return { label: "Future Value", value: tvmFv(pv, payment, rate, periods), suffix: "" };
    if (solveFor === "pv") {
      const value = r === 0 ? fv - payment * periods : (fv - payment * ((Math.pow(1 + r, periods) - 1) / r)) / Math.pow(1 + r, periods);
      return { label: "Present Value", value, suffix: "" };
    }
    if (solveFor === "pmt") {
      const value = r === 0 ? (fv - pv) / periods : (fv - pv * Math.pow(1 + r, periods)) * r / (Math.pow(1 + r, periods) - 1);
      return { label: "Payment", value, suffix: "" };
    }
    if (solveFor === "n") {
      const value = r === 0 ? (fv - pv) / payment : Math.log((fv + payment / r) / (pv + payment / r)) / Math.log(1 + r);
      return { label: "Number of Periods", value: Number.isFinite(value) ? value : 0, suffix: " periods" };
    }
    return { label: "Interest Rate", value: solveRate(pv, fv, payment, periods), suffix: "%" };
  }, [solveFor, pv, fv, periods, rate, payment]);

  const cashFlowRows = Array.from({ length: Math.min(40, Math.max(1, Math.ceil(periods))) }, (_, index) => {
    const period = index + 1;
    const start = tvmFv(solveFor === "pv" ? result.value : pv, payment, solveFor === "rate" ? result.value : rate, period - 1);
    const interest = start * ((solveFor === "rate" ? result.value : rate) / 100);
    const end = start + interest + payment;
    return { period, start, payment, interest, end };
  });
  const comparisonRows = [3, 5, 7, 10, 15].map((rowRate) => ({
    rate: rowRate,
    y1: 1000 * Math.pow(1 + rowRate / 100, 1),
    y5: 1000 * Math.pow(1 + rowRate / 100, 5),
    y10: 1000 * Math.pow(1 + rowRate / 100, 10),
    y20: 1000 * Math.pow(1 + rowRate / 100, 20),
  }));
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  return (
    <>
      <SEOHead title="Free Finance Calculator Online - Calculate Time Value of Money Instantly | CalcHive" description="Free online finance calculator. Solve for present value, future value, interest rate, payment or periods using time value of money instantly. 100% free, no signup required." canonical="/finance-calculator" keywords="free finance calculator, time value of money calculator free, TVM calculator free online, present value future value calculator free, financial calculator free online" category="Financial Calculators" breadcrumbName="Free Finance Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Finance Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Solve for present value, future value, number of periods, interest rate, or payment with a universal TVM calculator.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Solve for</label><select value={solveFor} onChange={(e) => setSolveFor(e.target.value as SolveFor)} className={inputClass}><option value="pv">Present Value</option><option value="fv">Future Value</option><option value="n">Number of Periods</option><option value="rate">Interest Rate</option><option value="pmt">Payment</option></select></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Present value</label><input type="number" value={pv} onChange={(e) => setPv(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Future value</label><input type="number" value={fv} onChange={(e) => setFv(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Number of periods</label><input type="number" value={periods} onChange={(e) => setPeriods(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate per period (%)</label><input type="number" step="0.1" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div>
            <div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Payment per period</label><input type="number" value={payment} onChange={(e) => setPayment(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <motion.div key={`${solveFor}-${pv}-${fv}-${periods}-${rate}-${payment}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.label}</p><p className="text-5xl sm:text-6xl font-black text-white tracking-tight" data-testid="result-finance">{result.suffix === "%" ? `${result.value.toFixed(3)}%` : result.suffix ? `${result.value.toFixed(2)}${result.suffix}` : money(result.value)}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Time Value of Money for Free</h2><p className="text-muted-foreground leading-relaxed">This TVM calculator uses present value, future value, rate, periods, and payment to solve for the missing financial variable.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Solve for PV FV Rate Payment and Periods</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Time Value of Money - How $1,000 Grows</caption><thead className="bg-muted/60"><tr>{["Rate", "1 Year", "5 Years", "10 Years", "20 Years"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparisonRows.map((row) => <tr key={row.rate} className="hover:bg-muted/30"><td className="py-2.5 px-3 font-semibold">{row.rate}%</td><td className="py-2.5 px-3">{money(row.y1)}</td><td className="py-2.5 px-3">{money(row.y5)}</td><td className="py-2.5 px-3">{money(row.y10)}</td><td className="py-2.5 px-3">{money(row.y20)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free TVM Financial Calculator for Students and Everyone</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Cash Flow Table</caption><thead className="bg-muted/60"><tr>{["Period", "Starting Value", "Payment", "Interest", "Ending Value"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{cashFlowRows.map((row) => <tr key={row.period} className="hover:bg-muted/30"><td className="py-2.5 px-3 font-semibold">{row.period}</td><td className="py-2.5 px-3">{money(row.start)}</td><td className="py-2.5 px-3">{money(row.payment)}</td><td className="py-2.5 px-3">{money(row.interest)}</td><td className="py-2.5 px-3 text-sky-600 dark:text-sky-400 font-semibold">{money(row.end)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/finance-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


